############################################################ # PG Setup Code ############################################################ @x=(0..23); @y=(5.87,5.54,4.66,3.45,2.23,1.34,1.02,1.37,2.33,3.65,4.96,5.92,6.27,5.83,4.64,3.00,1.37,0.18,-0.26,0.19,1.41,3.07,4.74,5.95); %f=map{$x[$_] => $y[$_]}(0..23); @hr=num_sort(random_subset(4,@x)); @r=map{Real(($f{$hr[2*$_+1]}-$f{$hr[2*$_]})/($hr[2*$_+1]-$hr[2*$_]))}(0,1); @r=map{NumberWithUnits("$_ ft/hr")}(@r); Context("Interval"); $d=List('[0,6],[12,18]'); $p=join(' ',(map{"($x[$_],$y[$_])"}(0..23))); $s=Interval('[21,22]'); $t=NumberWithUnits($y[22]-$y[21],"ft/hr");
