############################################################ # Section ############################################################ Section::Begin("");
BEGIN_PGML Find the rate of change in the tide level between hours [$hr[0]] and [$hr[1]].
[_]{$r[0]}{10}
END_PGML
############################################################ # Solution ############################################################
BEGIN_PGML_SOLUTION To find the rate of change between hours [$hr[0]] and [$hr[1]], calculate
[``` \frac{[$f{$hr[1]}]-[$f{$hr[0]}]}{[$hr[1]]-[$hr[0]]}=[$r[0]] \text{.}```]
END_PGML_SOLUTION
Section::End();
############################################################ # Section ############################################################ Section::Begin("");
BEGIN_PGML And what was the rate of change between hours [$hr[2]] and [$hr[3]]?
[_]{$r[1]}{10}
END_PGML
############################################################ # Solution ############################################################
BEGIN_PGML_SOLUTION To find the rate of change between hours [$hr[2]] and [$hr[3]], calculate
[``` \frac{[$f{$hr[3]}]-[$f{$hr[2]}]}{[$hr[3]]-[$hr[2]]}=[$r[1]] \text{.}```]
END_PGML_SOLUTION
Section::End();
############################################################ # Section ############################################################ Section::Begin("");
BEGIN_PGML List the longest intervals where there is a negative rate of change without any times in between that have positive rates of change.
[_]{$d}{20}
END_PGML
############################################################ # Solution ############################################################
BEGIN_PGML_SOLUTION The rate of change is negative from hour 0 to hour 6, and again from hour 12 to hour 18. So the intervals are [$d].
END_PGML_SOLUTION
Section::End();
############################################################ # Section ############################################################ Section::Begin("");
BEGIN_PGML Over which hour-long interval was the rate of change highest?
[_]{$s}{20}
END_PGML
############################################################ # Solution ############################################################
BEGIN_PGML_SOLUTION The steepest rate of change happens from hour 21 to hour 22. To find this, we can calculate each of the rates of change from one hour to the next, and the largest result happens from hour 21 to hour 22.
END_PGML_SOLUTION
Section::End();
############################################################ # Section ############################################################ Section::Begin("");
BEGIN_PGML What was that rate of change?
[_]{$t}{10}
END_PGML
############################################################ # Solution ############################################################
BEGIN_PGML_SOLUTION Between hour 21 and 22:
[``` \frac{[$y[22]] - [$y[21]]}{22 - 21} = [$t] ```]
END_PGML_SOLUTION
